sql:
SELECT ticker, company_name, market_cap
FROM securities
WHERE market_cap > (SELECT AVG(market_cap) FROM securities);

SELECT sector_name
FROM sector_information
WHERE sector_id = 10;

SELECT AVG(market_cap) AS average_market_cap
FROM securities
WHERE sector_id = 'TheSectorID';

SELECT market_cap
FROM securities
ORDER BY market_cap DESC;

SELECT * 
FROM sector_information 
WHERE parent_sector_id = 5;

external_knowledge:
- Financial beacons metaphorically refer to the ticker symbols of the securities;
- Shine brighter than the average lighthouse is a metaphor for having a total revenue greater than the average revenue of companies;
- Brightness in terms of revenue refers to the total revenue of each security.

sql:
SELECT COUNT(al.access_id) 
FROM access_logs al 
WHERE al.access_date BETWEEN date('now', '-1 month') AND date('now');

SELECT COUNT(*) AS total_companies, AVG(market_cap) AS average_market_cap
FROM securities
WHERE sector_id = 1;
